	GSD.length_verification = in.lookups;
	GSD.verification = (unsigned long *) malloc( GSD.length_verification * sizeof(unsigned long) );
	assert(GSD.verification != NULL);

	// Launch kernel
	int num_blocks = (in.lookups + 255) / 256;
	xs_lookup_kernel_baseline<<<num_blocks, 256>>>(in, GSD);

	// Copy verification array back to host
	unsigned long * h_verification = (unsigned long *) malloc( GSD.length_verification * sizeof(unsigned long) );
